import React from 'react';
import { Plex as CarbonPlex } from '@carbon/react';

const Plex = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonPlex
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonPlex>
    );
};

Plex.defaultProps = {
    className: ''
};

export default Plex;
